// ─── HISTORY PAGE ───────────────────────────────────────────────────────────
function HistoryPage() {
  const [idx, setIdx] = useState(0);
  const [imgErr, setImgErr] = useState(false);
  const [animKey, setAnimKey] = useState(0);
  const [playing, setPlaying] = useState(false);
  const [shareToast, setShareToast] = useState(false);
  const playRef = useRef(false);
  const ev = timelineData[idx];

  const handleShare = () => {
    const text = `${ev.year}: ${ev.title} — ${ev.desc}`;
    if (navigator.share) {
      navigator.share({ title: `${ev.year}: ${ev.title}`, text: ev.desc, url: window.location.href }).catch(() => {});
    } else {
      navigator.clipboard.writeText(text).then(() => {
        setShareToast(true);
        setTimeout(() => setShareToast(false), 2200);
      }).catch(() => {});
    }
  };

  useEffect(() => {
    setImgErr(false);
    setAnimKey(k => k + 1);
    const b = document.getElementById(`tl-b-${idx}`);
    if (b) b.scrollIntoView({ behavior: "smooth", block: "nearest", inline: "center" });
  }, [idx]);

  useEffect(() => {
    playRef.current = playing;
  }, [playing]);

  useEffect(() => {
    if (!playing) return;
    const iv = setInterval(() => {
      setIdx(i => {
        if (i >= timelineData.length - 1) { setPlaying(false); return i; }
        return i + 1;
      });
    }, 3000);
    return () => clearInterval(iv);
  }, [playing]);

  const go = (i) => { if (i >= 0 && i < timelineData.length) setIdx(i); };
  const advance10 = () => { setIdx(i => Math.min(i + 10, timelineData.length - 1)); };

  return (
    <div>
      <PageHero title="History of Des Moines" subtitle="From a frontier fort to a modern metropolis — explore 180+ years of milestones that shaped Iowa's capital." />
      <div style={{ maxWidth: 1100, margin: "0 auto", padding: "48px 32px 80px", background: "rgba(247, 237, 212, 0.4)", borderRadius: 0 }}>
        {/* Timeline bar */}
        <div className="tl-scroll" style={{
          display: "flex", gap: 6, overflowX: "auto", padding: "14px 20px",
          background: "var(--charcoal)", borderRadius: 14, marginBottom: 32,
          boxShadow: "0 4px 24px rgba(0,0,0,0.12)",
        }}>
          {timelineData.map((e, i) => (
            <button key={i} id={`tl-b-${i}`} onClick={() => go(i)} style={{
              flexShrink: 0, minWidth: 52, height: 36, borderRadius: 18,
              background: i === idx ? "var(--peach)" : "rgba(139,94,60,0.15)",
              color: i === idx ? "var(--charcoal)" : "rgba(255,255,255,0.5)",
              border: "none", fontSize: "0.72rem", fontWeight: i === idx ? 700 : 500,
              cursor: "pointer", transition: "all 0.3s cubic-bezier(0.16,1,0.3,1)",
              fontFamily: "'DM Sans', sans-serif", padding: "0 12px",
              transform: i === idx ? "scale(1.08)" : "scale(1)",
              boxShadow: i === idx ? "0 0 16px rgba(139,94,60,0.35)" : "none",
            }}>{e.year}</button>
          ))}
        </div>

        {/* Content card */}
        <div key={animKey} style={{
          display: "flex", background: "var(--cream)", borderRadius: 8, border: "1px solid #8B5E3C",
          overflow: "hidden", boxShadow: "0 12px 48px rgba(0,0,0,0.08)",
          minHeight: 400, animation: "scaleIn 0.35s cubic-bezier(0.16,1,0.3,1)",
          flexWrap: "wrap",
        }}>
          <div style={{
            flex: "1 1 340px", minHeight: 320, background: "#e0dcd7",
            display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden",
          }}>
            {!imgErr ? (
              <img src={ev.imageUrl} alt={ev.title} onError={() => setImgErr(true)}
                style={{ width: "100%", height: "100%", objectFit: "cover", display: "block", animation: "fadeIn 0.5s ease" }} />
            ) : (
              <div style={{ textAlign: "center", padding: 32, color: "var(--mist)" }}>
                <div style={{ fontSize: "2.5rem", marginBottom: 8 }}>🖼️</div>
                <div style={{ fontSize: "0.85rem" }}>Image unavailable</div>
              </div>
            )}
          </div>

          <div style={{
            flex: "1.2 1 360px", padding: "48px 44px",
            display: "flex", flexDirection: "column", justifyContent: "center",
          }}>
            <div style={{
              fontFamily: "'Playfair Display', serif", fontSize: "3.4rem",
              color: "var(--peach)", fontWeight: 700, lineHeight: 1, marginBottom: 6,
              animation: "slideInRight 0.5s ease",
            }}>{ev.year}</div>
            <h3 style={{
              fontSize: "1.4rem", fontWeight: 700, marginBottom: 16,
              color: "var(--charcoal)", animation: "slideInRight 0.5s ease 0.05s both",
            }}>{ev.title}</h3>
            <p style={{
              color: "var(--mist)", fontSize: "1rem", lineHeight: 1.7, marginBottom: 32,
              animation: "slideInRight 0.5s ease 0.1s both",
            }}>{ev.desc}</p>
            <div style={{ display: "flex", gap: 10, flexWrap: "wrap", animation: "fadeUp 0.5s ease 0.15s both" }}>
              <button onClick={() => go(idx - 1)} disabled={idx === 0} style={{
                padding: "11px 24px", borderRadius: 10, border: "none",
                background: idx === 0 ? "#ddd" : "var(--charcoal)",
                color: idx === 0 ? "#aaa" : "#fff", fontWeight: 600,
                cursor: idx === 0 ? "not-allowed" : "pointer",
                fontSize: "0.88rem", fontFamily: "'DM Sans', sans-serif",
                transition: "all 0.2s ease",
              }}>← Prev</button>
              <button onClick={() => go(idx + 1)} disabled={idx === timelineData.length - 1} style={{
                padding: "11px 24px", borderRadius: 10, border: "none",
                background: idx === timelineData.length - 1 ? "#ddd" : "var(--charcoal)",
                color: idx === timelineData.length - 1 ? "#aaa" : "#fff", fontWeight: 600,
                cursor: idx === timelineData.length - 1 ? "not-allowed" : "pointer",
                fontSize: "0.88rem", fontFamily: "'DM Sans', sans-serif",
                transition: "all 0.2s ease",
              }}>Next →</button>
              <button onClick={advance10} disabled={idx >= timelineData.length - 1} style={{
                padding: "11px 24px", borderRadius: 10, border: "none",
                background: idx >= timelineData.length - 1 ? "#ddd" : "var(--copper)",
                color: idx >= timelineData.length - 1 ? "#aaa" : "#fff", fontWeight: 600,
                cursor: idx >= timelineData.length - 1 ? "not-allowed" : "pointer",
                fontSize: "0.88rem", fontFamily: "'DM Sans', sans-serif",
                transition: "all 0.2s ease",
              }}>+10 Years →→</button>
              <button onClick={() => setPlaying(p => !p)} style={{
                padding: "11px 24px", borderRadius: 6, border: "2px solid var(--peach)",
                background: playing ? "var(--peach)" : "transparent",
                color: playing ? "#F2E8D5" : "var(--peach)", fontWeight: 600,
                cursor: "pointer", fontSize: "0.88rem",
                fontFamily: "'DM Sans', sans-serif", transition: "all 0.2s ease",
              }} aria-pressed={playing}>{playing ? "⏸ Pause" : "▶ Play"}</button>
              <button onClick={handleShare} style={{
                padding: "11px 24px", borderRadius: 10, border: "2px solid rgba(0,0,0,0.08)",
                background: "transparent", color: "var(--slate)", fontWeight: 600,
                cursor: "pointer", fontSize: "0.88rem",
                fontFamily: "'DM Sans', sans-serif", transition: "all 0.2s ease",
              }} aria-label="Share this historical event">📤 Share</button>
            </div>
          </div>
        </div>

        <p style={{ textAlign: "center", marginTop: 20, fontSize: "0.8rem", color: "var(--mist)" }}>
          {idx + 1} of {timelineData.length} events · Click any year to jump
        </p>

        {/* Share toast */}
        {shareToast && (
          <div style={{
            position: "fixed", bottom: 28, left: "50%", transform: "translateX(-50%)",
            background: "var(--charcoal)", color: "#fff", padding: "12px 24px",
            borderRadius: 12, fontSize: "0.88rem", fontWeight: 600, zIndex: 9000,
            animation: "fadeUp 0.3s ease", boxShadow: "0 8px 32px rgba(0,0,0,0.25)",
          }} role="status" aria-live="polite">
            ✅ Copied to clipboard!
          </div>
        )}

        {/* Population chart section */}
        <div style={{ marginTop: 64 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 32 }}>
            <div style={{ width: 32, height: 2, background: "var(--peach)", borderRadius: 1 }} />
            <span style={{ fontSize: "0.7rem", fontWeight: 700, letterSpacing: "0.15em", textTransform: "uppercase", color: "var(--copper)" }}>
              By the Numbers
            </span>
          </div>
          <PopulationChart />
        </div>
      </div>
    </div>
  );
}

