// ─── HEROES PAGE ────────────────────────────────────────────────────────────
function HeroesPage() {
  const [modal, setModal] = useState(null);
  const [answers, setAnswers] = useState({});
  const score = Object.values(answers).filter(a => a.correct).length;
  const allDone = Object.keys(answers).length === quizData.length;

  return (
    <div>
      <PageHero title="Heroes of Des Moines" subtitle="Meet the pioneers, activists, leaders, and visionaries who shaped Iowa's capital city." />
      <div style={{ maxWidth: 1100, margin: "0 auto", padding: "48px 32px" }}>
        <FadeSection><SectionLabel text="Notable Figures" /></FadeSection>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(230px, 1fr))", gap: 20, marginBottom: 64 }}>
          {heroesData.map((hero, i) => (
            <FadeSection key={i} delay={i * 0.06}>
              <div onClick={() => setModal(i)} style={{
                background: "var(--cream)", borderRadius: 8, overflow: "hidden", border: "1px solid #8B5E3C",
                cursor: "pointer", transition: "all 0.35s cubic-bezier(0.16,1,0.3,1)",
                boxShadow: "0 2px 12px rgba(44,24,16,0.1)",
              }}
              onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-8px)"; e.currentTarget.style.boxShadow = "0 20px 48px rgba(0,0,0,0.12)"; }}
              onMouseLeave={e => { e.currentTarget.style.transform = ""; e.currentTarget.style.boxShadow = "0 2px 12px rgba(0,0,0,0.04)"; }}
              >
                <div style={{ height: 200, background: "#e0dcd7", overflow: "hidden" }}>
                  <img src={hero.image} alt={hero.name} onError={e => e.target.style.display = "none"}
                    style={{ width: "100%", height: "100%", objectFit: "cover", transition: "transform 0.5s" }} />
                </div>
                <div style={{ padding: "18px 20px" }}>
                  <div style={{ fontWeight: 700, fontSize: "1.08rem", marginBottom: 4 }}>{hero.name}</div>
                  <div style={{ fontSize: "0.68rem", color: "var(--copper)", fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: 10 }}>{hero.title}</div>
                  <div style={{ fontSize: "0.84rem", color: "var(--mist)", lineHeight: 1.5 }}>{hero.shortDesc}</div>
                </div>
              </div>
            </FadeSection>
          ))}
        </div>

        <FadeSection><SectionLabel text="Test Your Knowledge" /></FadeSection>
        <FadeSection delay={0.1}>
          <div style={{ background: "var(--cream)", borderRadius: 8, padding: "36px 32px", boxShadow: "0 4px 20px rgba(44,24,16,0.1)", borderTop: "4px solid var(--peach)" }}>
            <h2 style={{ fontFamily: "'Playfair Display', serif", fontSize: "1.6rem", marginBottom: 24, textAlign: "center" }}>Did You Know?</h2>
            {quizData.map((q, qi) => (
              <div key={qi} style={{ background: "#F2E8D5", borderRadius: 6, padding: 20, marginBottom: 14, border: "1px solid #8B5E3C" }}>
                <div style={{ fontWeight: 700, marginBottom: 12, fontSize: "0.95rem" }}>{qi + 1}. {q.question}</div>
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
                  {q.options.map((opt, oi) => {
                    const answered = answers[qi] !== undefined;
                    const isCorrect = oi === q.correct;
                    const wasSelected = answers[qi]?.selected === oi;
                    let bg = "white", border = "2px solid #e0e0e0", color = "var(--charcoal)";
                    if (answered && isCorrect) { bg = "var(--success)"; border = "2px solid var(--success)"; color = "#fff"; }
                    if (answered && wasSelected && !isCorrect) { bg = "var(--danger)"; border = "2px solid var(--danger)"; color = "#fff"; }
                    return (
                      <button key={oi} disabled={answered} onClick={() => setAnswers(p => ({ ...p, [qi]: { selected: oi, correct: isCorrect } }))} style={{
                        background: bg, border, color, borderRadius: 8, padding: "10px 14px", fontSize: "0.88rem", fontWeight: 500,
                        cursor: answered ? "default" : "pointer", textAlign: "left", fontFamily: "'DM Sans', sans-serif",
                        transition: "all 0.2s ease", opacity: answered && !isCorrect && !wasSelected ? 0.45 : 1,
                      }}>{opt}</button>
                    );
                  })}
                </div>
              </div>
            ))}
            {allDone && (
              <div style={{ textAlign: "center", marginTop: 20, padding: 16, fontWeight: 700, fontSize: "1.1rem", borderTop: "2px dashed rgba(0,0,0,0.08)" }}>
                You scored {score} out of {quizData.length}! {score === quizData.length ? " 🎉 Perfect!" : ""}
              </div>
            )}
          </div>
        </FadeSection>
      </div>

      {modal !== null && (
        <div onClick={() => setModal(null)} style={{
          position: "fixed", inset: 0, background: "rgba(44,24,16,0.8)",
          backdropFilter: "blur(8px)", display: "flex", alignItems: "center",
          justifyContent: "center", zIndex: 1000, padding: 16, animation: "fadeIn 0.25s ease",
        }}>
          <div onClick={e => e.stopPropagation()} style={{
            background: "var(--cream)", borderRadius: 8, maxWidth: 700, width: "100%",
            display: "flex", overflow: "hidden", maxHeight: "85vh",
            boxShadow: "0 24px 72px rgba(0,0,0,0.35)", flexWrap: "wrap",
            animation: "scaleIn 0.3s cubic-bezier(0.16,1,0.3,1)",
          }}>
            <div style={{ flex: "0 0 38%", minWidth: 200, background: "#e0dcd7", minHeight: 240 }}>
              <img src={heroesData[modal].image} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
            </div>
            <div style={{ flex: 1, padding: 32, overflowY: "auto", position: "relative", minWidth: 260 }}>
              <button onClick={() => setModal(null)} style={{
                position: "absolute", top: 12, right: 16, background: "none",
                border: "none", fontSize: "1.5rem", cursor: "pointer", color: "var(--mist)",
              }}>×</button>
              <h2 style={{ fontFamily: "'Playfair Display', serif", fontSize: "1.6rem", marginBottom: 4 }}>{heroesData[modal].name}</h2>
              <div style={{ fontSize: "0.72rem", color: "var(--copper)", fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: 16 }}>{heroesData[modal].title}</div>
              <p style={{ color: "var(--mist)", lineHeight: 1.7, fontSize: "0.92rem", marginBottom: 20 }}>{heroesData[modal].longDesc}</p>
              <div style={{ borderTop: "1px solid #eee", paddingTop: 16 }}>
                <div style={{ fontWeight: 700, marginBottom: 8, fontSize: "0.9rem" }}>Key Achievements</div>
                {heroesData[modal].achievements.map((a, i) => (
                  <div key={i} style={{ display: "flex", gap: 8, alignItems: "baseline", marginBottom: 6, fontSize: "0.85rem", color: "var(--mist)" }}>
                    <span style={{ color: "var(--peach)", fontWeight: 700 }}>•</span> {a}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

