function VoicesPage() {
  const [expandedHidden, setExpandedHidden] = useState(null);
  const [voicesSection, setVoicesSection] = useState("newspapers");
  const tlRefs = useRef([]);

  useEffect(() => {
    if (voicesSection !== "timeline") return;
    // Small timeout lets React flush the DOM before observing
    const timer = setTimeout(() => {
      const obs = new IntersectionObserver(
        (entries) => {
          entries.forEach(e => {
            if (e.isIntersecting) {
              e.target.style.opacity = "1";
              e.target.style.transform = "translateY(0)";
            }
          });
        },
        { threshold: 0.08 }
      );
      tlRefs.current.forEach(r => { if (r) obs.observe(r); });
      return () => obs.disconnect();
    }, 80);
    return () => clearTimeout(timer);
  }, [voicesSection]);

  return (
    <div>
      <PageHero title="Voices" subtitle="Oral histories, hidden history, and the diverse stories that complete the full picture of Des Moines." />

      {/* Tab navigation — right below page hero */}
      <div style={{
        background: "rgba(247, 237, 212, 0.92)",
        backdropFilter: "blur(8px)",
        borderBottom: "2px solid rgba(120, 80, 30, 0.2)",
        position: "sticky", top: 60, zIndex: 90,
        boxShadow: "0 2px 8px rgba(28, 16, 8, 0.08)",
      }}>
        <div style={{ maxWidth: 1100, margin: "0 auto", padding: "0 32px", display: "flex", gap: 0, overflowX: "auto" }}>
          {[
            { id: "newspapers", label: "📰 From the Archives" },
            { id: "oral", label: "Oral Histories" },
            { id: "hidden", label: "Hidden History" },
            { id: "timeline", label: "Voices Timeline" },
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => setVoicesSection(tab.id)}
              style={{
                padding: "14px 20px", background: "none",
                border: "none", cursor: "pointer",
                fontFamily: "'Playfair Display', serif",
                fontWeight: voicesSection === tab.id ? 700 : 500,
                fontSize: "0.88rem", letterSpacing: "0.03em",
                color: voicesSection === tab.id ? "var(--charcoal)" : "var(--mist)",
                borderBottom: voicesSection === tab.id ? "3px solid var(--peach)" : "3px solid transparent",
                marginBottom: "-2px", transition: "all 0.2s", whiteSpace: "nowrap",
              }}
            >{tab.label}</button>
          ))}
        </div>
      </div>

      <div style={{ maxWidth: 1100, margin: "0 auto", padding: "48px 32px 80px" }}>

        {voicesSection === "newspapers" && <>
          <NewspaperSection />
        </>}

        {voicesSection === "oral" && <>
        <FadeSection>
          <SectionLabel text="Oral Histories" />
          <p style={{ color: "var(--charcoal)", fontSize: "1.05rem", marginBottom: 6, maxWidth: 680, fontWeight: 700 }}>
            Real voices. Real stories.
          </p>
          <p style={{ color: "var(--charcoal)", fontSize: "0.95rem", marginBottom: 32, maxWidth: 680, lineHeight: 1.7, opacity: 0.75 }}>
            Short, transcribed accounts from <strong>community members across decades of Des Moines history</strong> — 
            capturing the everyday experiences that shaped the city's identity.
          </p>
        </FadeSection>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))", gap: 20, marginBottom: 64 }}>
          {ORAL_HISTORIES.map((h, i) => (
            <FadeSection key={i} delay={i * 0.07}>
              <div style={{
                background: "var(--cream)", borderRadius: 10, padding: "26px 24px",
                border: "1px solid rgba(120,80,30,0.14)",
                borderLeft: "3px solid var(--peach)",
                boxShadow: "0 2px 14px rgba(28,16,8,0.09)",
                transition: "all 0.25s ease", height: "100%",
              }}
              onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-4px)"; e.currentTarget.style.boxShadow = "0 10px 28px rgba(28,16,8,0.14)"; }}
              onMouseLeave={e => { e.currentTarget.style.transform = ""; e.currentTarget.style.boxShadow = "0 2px 14px rgba(28,16,8,0.09)"; }}
              >
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 14 }}>
                  <div>
                    <div style={{ fontWeight: 700, fontSize: "1.05rem", color: "var(--charcoal)", marginBottom: 2 }}>{h.name}</div>
                    <div style={{ fontSize: "0.72rem", color: "var(--copper)", fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.09em" }}>{h.tag}</div>
                  </div>
                  <div style={{ fontSize: "1.5rem", fontWeight: 700, color: "var(--peach)", fontFamily: "'Playfair Display', serif", flexShrink: 0, marginLeft: 12 }}>{h.year}</div>
                </div>
                <p style={{ color: "var(--mist)", fontSize: "0.88rem", lineHeight: 1.7, fontStyle: "italic", margin: 0 }}>"{h.excerpt}"</p>
              </div>
            </FadeSection>
          ))}
        </div>
        </>}

        {voicesSection === "hidden" && <>
        <FadeSection>
          <SectionLabel text="Hidden History" />
          <p style={{ color: "var(--charcoal)", fontSize: "1.05rem", marginBottom: 6, maxWidth: 680, fontWeight: 700 }}>
            The stories left out of the textbooks.
          </p>
          <p style={{ color: "var(--charcoal)", fontSize: "0.95rem", marginBottom: 32, maxWidth: 680, lineHeight: 1.7, opacity: 0.75 }}>
            <strong>Lesser-known events and diverse communities</strong> that shaped Des Moines but rarely appear in 
            standard histories — from the all-Black city of Buxton to the Latino community of the Near South Side.
          </p>
        </FadeSection>

        <div style={{ display: "flex", flexDirection: "column", gap: 16, marginBottom: 72 }}>
          {HIDDEN_HISTORY.map((h, i) => (
            <FadeSection key={i} delay={i * 0.06}>
              <div style={{
                background: "var(--cream)", borderRadius: 8,
                boxShadow: "0 2px 12px rgba(44,24,16,0.08)",
                overflow: "hidden", transition: "all 0.3s ease",
              }}>
                <button
                  onClick={() => setExpandedHidden(expandedHidden === i ? null : i)}
                  style={{
                    width: "100%", padding: "22px 28px", display: "flex", alignItems: "center",
                    justifyContent: "space-between", background: "none", border: "none",
                    cursor: "pointer", textAlign: "left", fontFamily: "'DM Sans', sans-serif",
                  }}
                >
                  <div>
                    <div style={{ fontWeight: 700, fontSize: "1.05rem", color: "var(--charcoal)", marginBottom: 4 }}>{h.title}</div>
                    <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
                      <span style={{ fontSize: "0.72rem", color: "var(--copper)", fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.09em" }}>{h.tag}</span>
                      <span style={{ fontSize: "0.78rem", color: "var(--mist)" }}>{h.period}</span>
                    </div>
                  </div>
                  <span style={{ fontSize: "1.2rem", color: "var(--peach)", flexShrink: 0, marginLeft: 16, transition: "transform 0.3s", transform: expandedHidden === i ? "rotate(45deg)" : "rotate(0)" }}>+</span>
                </button>
                {expandedHidden === i && (
                  <div style={{ padding: "0 28px 24px", borderTop: "1px solid rgba(0,0,0,0.06)" }}>
                    <p style={{ color: "var(--mist)", fontSize: "0.92rem", lineHeight: 1.75, marginTop: 16, marginBottom: 0 }}>{h.desc}</p>
                  </div>
                )}
              </div>
            </FadeSection>
          ))}
        </div>
        </>}

        {voicesSection === "timeline" && <>
        <FadeSection>
          <SectionLabel text="Dynamic Timeline" />
          <p style={{ color: "var(--charcoal)", fontSize: "1.05rem", marginBottom: 6, maxWidth: 680, fontWeight: 700 }}>
            A city built by many voices.
          </p>
          <p style={{ color: "var(--charcoal)", fontSize: "0.95rem", marginBottom: 48, maxWidth: 680, lineHeight: 1.7, opacity: 0.75 }}>
            Scroll through the <strong>voices and events that shaped the diverse story of Des Moines</strong> — 
            from indigenous homeland to modern metropolis, told through the communities who lived it.
          </p>
        </FadeSection>

        <div style={{ position: "relative", paddingLeft: 32 }}>
          <div style={{
            position: "absolute", left: 16, top: 0, bottom: 0,
            width: 2, background: "linear-gradient(to bottom, var(--peach), var(--copper))",
            borderRadius: 1,
          }} />
          {VOICES_TIMELINE.map((t, i) => (
            <div
              key={i}
              ref={el => tlRefs.current[i] = el}
              style={{
                display: "flex", gap: 24, marginBottom: 40,
                opacity: 0, transform: "translateY(24px)",
                transition: `opacity 0.55s ease ${i * 0.04}s, transform 0.55s ease ${i * 0.04}s`,
              }}
            >
              <div style={{
                position: "absolute", left: 9, width: 16, height: 16,
                borderRadius: "50%", background: t.color,
                border: "3px solid #fff", boxShadow: "0 0 0 2px " + t.color,
                flexShrink: 0, marginTop: 4,
              }} />
              <div style={{
                background: "var(--cream)", borderRadius: 8, padding: "20px 24px",
                boxShadow: "0 2px 12px rgba(44,24,16,0.08)", flex: 1,
                borderLeft: `3px solid ${t.color}`,
              }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 8, marginBottom: 8 }}>
                  <div>
                    <span style={{ fontWeight: 700, fontSize: "1rem", color: "var(--charcoal)" }}>{t.event}</span>
                    <span style={{
                      display: "inline-block", marginLeft: 12,
                      fontSize: "0.68rem", fontWeight: 700, textTransform: "uppercase",
                      letterSpacing: "0.08em", padding: "2px 8px", borderRadius: 20,
                      background: t.color + "22", color: t.color,
                    }}>{t.category}</span>
                  </div>
                  <span style={{ fontWeight: 700, fontSize: "1.1rem", color: t.color, fontFamily: "'Playfair Display', serif", flexShrink: 0 }}>{t.year}</span>
                </div>
                <p style={{ color: "var(--mist)", fontSize: "0.88rem", lineHeight: 1.65, margin: 0 }}>{t.desc}</p>
              </div>
            </div>
          ))}
        </div>
        </>}
      </div>

    </div>
  );
}

// ─── AGRICULTURE PAGE ───────────────────────────────────────────────────────
const AG_DATA = [
  { years: "1840s – 1880s", title: "From Prairie to Plow", desc: "<p>Long before it was a city, the land beneath Des Moines was shaped by retreating glaciers that left behind some of the deepest, darkest, and most fertile topsoil on the planet. When Fort Des Moines was established at the Raccoon Fork in 1843, early settlers quickly realized that the true gold of the region wasn't in minerals, but in the dirt.</p><p>Early agriculture was primarily subsistence farming, but the arrival of the railroad in 1866 changed everything. Des Moines transformed overnight from an isolated pioneer town into a massive shipping and processing hub. Farmers could now send their grain and livestock into the city to be packed and shipped across the expanding United States.</p>", img: "" },
  { years: "1890s – 1920s", title: "Publishing Capital of the Farm", desc: "<p>By the turn of the 20th century, Des Moines wasn't just shipping food; it was shipping <strong>ideas</strong>. The city became the undisputed agricultural publishing capital of the United States.</p><p>In 1902, Edwin T. Meredith founded <em>Successful Farming</em> magazine in Des Moines, which grew into a national media empire. Around the same time, the Wallace family was publishing <em>Wallaces' Farmer</em>, a massively influential newspaper that taught generations of American farmers about crop rotation, soil conservation, and livestock management. Des Moines became the intellectual brain-trust for the American farmer.</p>", img: "" },
  { years: "1920s – 1940s", title: "The Hybrid Revolution", desc: "<p>The most pivotal moment in Des Moines' agricultural history occurred in the 1920s, spearheaded by Henry A. Wallace (who would later become FDR's Vice President). Fascinated by genetics, Wallace began experimenting with corn breeding in his Des Moines backyard.</p><p>In 1926, he founded the <strong>Hi-Bred Corn Company</strong> (later Pioneer Hi-Bred) in Des Moines. By introducing hybrid corn seed to the market, Wallace effectively doubled crop yields worldwide, revolutionizing global agriculture. Des Moines was no longer just growing food—it was rewriting the DNA of how food was grown.</p>", img: "" },
  { years: "1950s – 1990s", title: "Rise of Modern Agribusiness", desc: "<p>Following World War II, farming evolved from family-run, labor-intensive operations into a highly mechanized, science-driven industry. Des Moines evolved right alongside it, transitioning into a hub for corporate agribusiness.</p><p>Major players established massive manufacturing hubs in the metro. <strong>John Deere</strong> expanded its footprint in neighboring Ankeny to build the massive machines needed for modern farming. <strong>Kemin Industries</strong>, founded in Des Moines in 1961, became a global powerhouse in nutritional ingredients and animal health. The city quickly became the home base for national commodity organizations.</p>", img: "" },
  { years: "1990s – Present", title: "The Geneva of Agriculture", desc: "<p>In the 1990s, local philanthropist John Ruan helped relocate the <strong>World Food Prize</strong>—created by Nobel Peace Prize laureate Dr. Norman Borlaug—permanently to Des Moines.</p><p>Often referred to as the 'Nobel Prize for Food and Agriculture,' this move cemented Des Moines' status on the global stage. Every October, the city hosts the Borlaug Dialogue, drawing international presidents, scientists, and agricultural CEOs to the stunning World Food Prize Hall of Laureates in downtown Des Moines to discuss solutions to global hunger and food security.</p>", img: "" },
  { years: "Today", title: "AgTech and Sustainability", desc: "<p>Today, agriculture in the Des Moines metro looks vastly different than it did in 1843. The plows have been joined by pixels. Companies like <strong>Corteva Agriscience</strong> use AI, drone mapping, and CRISPR gene editing to create climate-resilient crops.</p><p>The culture of agriculture also thrives locally through the <strong>Downtown Des Moines Farmers' Market</strong>, which reconnects urban residents with over 300 local farmers. Meanwhile, the region is heavily focused on sustainability—testing ground-breaking practices like cover crops and nutrient reduction strategies to protect the land and water for the next generation.</p>", img: "" },
];

