// ─── HISTORICAL MAP PAGE ──────────────────────────────────────────────────────
function HistoricalMapPage() {
  const mapRef = useRef(null);
  const mapInstanceRef = useRef(null);
  const [selected, setSelected] = useState(null);
  const [filter, setFilter] = useState("All");

  const categories = ["All", ...Array.from(new Set(MAP_LOCATIONS.map(l => l.category)))];
  const filtered = filter === "All" ? MAP_LOCATIONS : MAP_LOCATIONS.filter(l => l.category === filter);

  // Initialize map once
  useEffect(() => {
    if (!mapRef.current || mapInstanceRef.current) return;
    const map = L.map(mapRef.current, {
      center: [41.6100, -93.6600],
      zoom: 11,
      zoomControl: true,
    });
    L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
      attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>',
      maxZoom: 19,
    }).addTo(map);
    mapInstanceRef.current = map;
    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove();
        mapInstanceRef.current = null;
      }
    };
  }, []);

  // Refresh markers when filter or selection changes
  useEffect(() => {
    const map = mapInstanceRef.current;
    if (!map) return;
    map.eachLayer(layer => { if (layer instanceof L.Marker) map.removeLayer(layer); });
    filtered.forEach(loc => {
      const isSel = selected?.id === loc.id;
      const size = isSel ? 48 : 38;
      const icon = L.divIcon({
        html: `<div style="
          width:${size}px;height:${size}px;
          background:${isSel ? '#8B5E3C' : '#A0522D'};
          border:3px solid ${isSel ? '#6B3F1F' : '#8B5E3C'};
          border-radius:50%;
          box-shadow:0 4px 14px rgba(0,0,0,${isSel ? '0.3' : '0.18'});
          display:flex;align-items:center;justify-content:center;
          font-size:${isSel ? '22px' : '17px'};
          cursor:pointer;
          transition:all 0.2s;
        ">${loc.emoji}</div>`,
        className: '',
        iconSize: [size, size],
        iconAnchor: [size / 2, size / 2],
      });
      L.marker([loc.lat, loc.lng], { icon }).addTo(map).on('click', () => setSelected(loc));
      if (isSel) map.setView([loc.lat, loc.lng], Math.max(map.getZoom(), 14), { animate: true });
    });
  }, [filtered, selected]);

  const panelStyle = {
    background: "white",
    borderRadius: 16,
    padding: 28,
    boxShadow: "0 4px 24px rgba(0,0,0,0.08)",
    border: "1px solid rgba(0,0,0,0.06)",
  };

  return (
    <div style={{ minHeight: "100vh", background: "#F2E8D5" }}>
      <PageHero
        title="Interactive Historical Map"
        subtitle="Explore 180+ years of Des Moines history — click any marker to uncover the stories, people, and events that shaped Iowa's capital."
      />

      {/* Category filter */}
      <FadeSection>
        <div style={{ maxWidth: 1200, margin: "0 auto", padding: "24px 24px 0" }}>
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap", alignItems: "center" }}>
            <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "0.72rem", color: "var(--mist)", marginRight: 6, letterSpacing: "0.08em" }}>FILTER BY</span>
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => { setFilter(cat); setSelected(null); }}
                style={{
                  padding: "6px 14px",
                  borderRadius: 20,
                  border: filter === cat ? "1.5px solid var(--copper)" : "1.5px solid rgba(0,0,0,0.1)",
                  background: filter === cat ? "var(--peach)" : "white",
                  color: filter === cat ? "var(--charcoal)" : "var(--slate)",
                  fontFamily: "'DM Sans', sans-serif",
                  fontSize: "0.82rem",
                  fontWeight: filter === cat ? 600 : 400,
                  cursor: "pointer",
                  transition: "all 0.15s",
                }}
              >{cat}</button>
            ))}
          </div>
        </div>
      </FadeSection>

      {/* Map + sidebar layout */}
      <FadeSection delay={0.1}>
        <div style={{ maxWidth: 1200, margin: "24px auto 60px", padding: "0 24px", display: "flex", gap: 24, alignItems: "flex-start", flexWrap: "wrap" }}>

          {/* Leaflet map */}
          <div style={{ flex: "1 1 520px", borderRadius: 16, overflow: "hidden", boxShadow: "0 8px 40px rgba(0,0,0,0.12)", border: "1px solid rgba(0,0,0,0.08)", height: 560 }}>
            <div ref={mapRef} style={{ width: "100%", height: "100%" }} />
          </div>

          {/* Info panel */}
          <div style={{ flex: "1 1 300px", minWidth: 280 }}>
            {selected ? (
              <div style={{ ...panelStyle, animation: "fadeUp 0.35s ease" }}>
                <div style={{ fontSize: "2.4rem", marginBottom: 10 }}>{selected.emoji}</div>
                <span style={{
                  display: "inline-block",
                  background: "var(--peach)",
                  color: "var(--charcoal)",
                  fontSize: "0.7rem",
                  fontWeight: 600,
                  padding: "3px 10px",
                  borderRadius: 20,
                  fontFamily: "'JetBrains Mono', monospace",
                  letterSpacing: "0.06em",
                  marginBottom: 10,
                }}>{selected.category.toUpperCase()}</span>
                <h2 style={{ fontFamily: "'Playfair Display', serif", fontSize: "1.45rem", fontWeight: 700, color: "var(--charcoal)", marginBottom: 4, lineHeight: 1.25 }}>{selected.name}</h2>
                <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "0.78rem", color: "var(--copper)", marginBottom: 14 }}>Est. {selected.year}</div>
                <p style={{ fontSize: "0.93rem", lineHeight: 1.7, color: "var(--slate)", marginBottom: 16 }}>{selected.desc}</p>
                <div style={{ background: "#F2E8D5", borderRadius: 10, padding: "14px 16px", borderLeft: "3px solid var(--peach-dark)" }}>
                  <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "0.66rem", color: "var(--copper)", letterSpacing: "0.1em", marginBottom: 6 }}>DID YOU KNOW</div>
                  <p style={{ fontSize: "0.86rem", color: "var(--slate)", lineHeight: 1.6 }}>{selected.fact}</p>
                </div>
                <button
                  onClick={() => setSelected(null)}
                  style={{ marginTop: 16, background: "transparent", border: "1.5px solid rgba(0,0,0,0.12)", borderRadius: 8, padding: "8px 16px", fontSize: "0.82rem", color: "var(--mist)", cursor: "pointer", fontFamily: "'DM Sans', sans-serif" }}
                >← Back to list</button>
              </div>
            ) : (
              <div style={panelStyle}>
                <div style={{ textAlign: "center", paddingBottom: 16, borderBottom: "1px solid rgba(0,0,0,0.06)", marginBottom: 16 }}>
                  <div style={{ fontSize: "2.6rem", marginBottom: 10 }}>🗺️</div>
                  <h3 style={{ fontFamily: "'Playfair Display', serif", fontSize: "1.15rem", color: "var(--charcoal)", marginBottom: 8 }}>Select a Location</h3>
                  <p style={{ fontSize: "0.84rem", color: "var(--mist)", lineHeight: 1.6 }}>Click any marker on the map, or choose a site from the list below.</p>
                </div>
                <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "0.68rem", color: "var(--mist)", letterSpacing: "0.1em", marginBottom: 10 }}>
                  {filtered.length} LOCATION{filtered.length !== 1 ? "S" : ""}
                </div>
                <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                  {filtered.map(loc => (
                    <button
                      key={loc.id}
                      onClick={() => setSelected(loc)}
                      style={{ display: "flex", alignItems: "center", gap: 10, width: "100%", padding: "10px 12px", background: "#F2E8D5", border: "1px solid rgba(0,0,0,0.06)", borderRadius: 8, cursor: "pointer", textAlign: "left", transition: "all 0.15s" }}
                      onMouseEnter={e => { e.currentTarget.style.background = "var(--cream)"; e.currentTarget.style.borderColor = "var(--peach)"; }}
                      onMouseLeave={e => { e.currentTarget.style.background = "var(--warm)"; e.currentTarget.style.borderColor = "rgba(0,0,0,0.06)"; }}
                    >
                      <span style={{ fontSize: "1.1rem", flexShrink: 0 }}>{loc.emoji}</span>
                      <div>
                        <div style={{ fontSize: "0.83rem", fontWeight: 600, color: "var(--charcoal)" }}>{loc.name}</div>
                        <div style={{ fontSize: "0.71rem", color: "var(--mist)" }}>{loc.year} · {loc.category}</div>
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>

        </div>
      </FadeSection>
    </div>
  );
}

// ─── APP ─────────────────────────────────────────────────────────────────────
export default function App() {
  const [page, setPage] = useState("home");
  const [searchOpen, setSearchOpen] = useState(false);

  useEffect(() => {
    const handler = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === "k") {
        e.preventDefault();
        setSearchOpen(o => !o);
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, []);

  const navigate = (p) => { setPage(p); window.scrollTo({ top: 0, behavior: "smooth" }); if (typeof window.__playNavSound === "function") window.__playNavSound(); };
  const renderPage = () => {
    switch (page) {
      case "history": return <HistoryPage />;
      case "heroes": return <HeroesPage />;
      case "voices": return <VoicesPage />;
      case "play": return <PlayPage />;
      case "map": return <HistoricalMapPage />;
      case "sources": return <SourcesPage />;
      case "then-now": return <ThenNowPage />;
      case "neighborhoods": return <NeighborhoodPage />;
      default: return <HomePage setPage={navigate} />;
    }
  };
  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column" }}>
      <GlobalStyles />
      {/* Skip to main content — accessibility */}
      <a
        href="#main-content"
        style={{
          position: "absolute", top: -60, left: 16, zIndex: 10000,
          background: "var(--peach)", color: "#F2E8D5", padding: "10px 18px",
          borderRadius: 8, fontWeight: 700, textDecoration: "none", fontSize: "0.88rem",
          transition: "top 0.2s ease",
        }}
        onFocus={e => { e.currentTarget.style.top = "16px"; }}
        onBlur={e => { e.currentTarget.style.top = "-60px"; }}
      >
        Skip to main content
      </a>
      <Navbar activePage={page} setPage={navigate} onSearchOpen={() => setSearchOpen(true)} />
      <main id="main-content" style={{ flex: 1 }} tabIndex={-1}>{renderPage()}</main>
      <Footer setPage={navigate} />
      <SearchModal
        isOpen={searchOpen}
        onClose={() => setSearchOpen(false)}
        timelineData={timelineData}
        heroesData={heroesData}
        mapLocations={MAP_LOCATIONS}
        setPage={navigate}
      />
    </div>
  );
}
